// claimCountingStore wraps bead.Store and counts Claim invocations. The rest
// of ExecuteBeadLoopStore is delegated to the embedded *bead.Store.
type claimCountingStore struct {
	*bead.Store
	claimCalls  int32
	beforeClaim func()
}

func (s *claimCountingStore) Claim(id, assignee string) error {
	if s.beforeClaim != nil {
		s.beforeClaim()
	}
	atomic.AddInt32(&s.claimCalls, 1)
	return s.Store.Claim(id, assignee)
}

func (s *claimCountingStore) ClaimWithOptions(id, assignee, session, worktree string) error {
	if s.beforeClaim != nil {
		s.beforeClaim()
	}
	atomic.AddInt32(&s.claimCalls, 1)
	return s.Store.ClaimWithOptions(id, assignee, session, worktree)
}

func (s *claimCountingStore) TouchClaimHeartbeat(id string) error {
	return s.Store.TouchClaimHeartbeat(id)
}
func (s *claimCountingStore) Unclaim(id string) error              { return s.Store.Unclaim(id) }
func (s *claimCountingStore) ReadyExecution() ([]bead.Bead, error) { return s.Store.ReadyExecution() }
func (s *claimCountingStore) CloseWithEvidence(id, sessionID, commitSHA string) error {
	return s.Store.CloseWithEvidence(id, sessionID, commitSHA)
}
func (s *claimCountingStore) AppendEvent(id string, ev bead.BeadEvent) error {
	return s.Store.AppendEvent(id, ev)
}
func (s *claimCountingStore) Events(id string) ([]bead.BeadEvent, error) {
	return s.Store.Events(id)
}
func (s *claimCountingStore) SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error {
	return s.Store.SetExecutionCooldown(id, until, status, detail, baseRev)
}
func (s *claimCountingStore) IncrNoChangesCount(id string) (int, error) {
	return s.Store.IncrNoChangesCount(id)
}
func (s *claimCountingStore) Reopen(id, reason, notes string) error {
	return s.Store.Reopen(id, reason, notes)
}

// TestRoutingPreflightRejectionExitsLoopWithoutClaim covers ddx-98e6e9ef:
// when RoutePreflight returns the upstream typed-incompatibility error
// (agent.ErrHarnessModelIncompatible), the loop must fail during startup
// before any bead is claimed or executed.
// TestWatchSurvivesPerBeadRoutingFailureAndContinues verifies that a per-bead
// no_viable_provider routing failure no longer terminates a ddx work --watch
// drain (ddx-a827d07f). The watcher must attempt the next ready bead instead of
// exiting, and must leave the failed bead open and un-parked (no cooldown).
func TestWatchSurvivesPerBeadRoutingFailureAndContinues(t *testing.T) {
	inner, first, second := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	var execCount int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			// Once both ready beads have been attempted, the watcher has
			// demonstrably survived the first bead's routing failure; stop the
			// otherwise-infinite watch loop.
			if atomic.AddInt32(&execCount, 1) >= 2 {
				cancel()
			}
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusExecutionFailed,
				Detail:    "ResolveRoute: no live provider supports prompt of 1881 tokens with tools=false at policy cheap",
				SessionID: "sess-routing",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:         executeloop.ModeWatch,
		IdleInterval: 10 * time.Millisecond,
		ProjectRoot:  t.TempDir(),
		SessionID:    "sess-routing-loop",
		WorkerID:     "worker-routing",
	})
	require.NotNil(t, result)

	// The watcher continued past the first bead's routing failure to attempt the
	// second ready bead — the bug exited the worker after the first failure.
	assert.GreaterOrEqual(t, atomic.LoadInt32(&execCount), int32(2),
		"watcher must keep draining after a per-bead routing failure")
	assert.NotEqual(t, "routing_unavailable", result.ExitReason,
		"a per-bead routing failure must not become a worker-level routing_unavailable exit")
	assert.ErrorIs(t, err, context.Canceled)

	// Both beads remain open, unclaimed, and un-parked (no cooldown).
	for _, id := range []string{first.ID, second.ID} {
		got, getErr := inner.Get(context.Background(), id)
		require.NoError(t, getErr)
		assert.Equal(t, bead.StatusOpen, got.Status)
		assert.Empty(t, got.Owner)
		if got.Extra != nil {
			_, hasRetry := got.Extra["work-retry-after"]
			assert.False(t, hasRetry, "routing failure must not park the bead with a cooldown")
		}
	}
}

func TestRoutingPreflightRejectionExitsLoopWithoutClaim(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	var execCount int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCount, 1)
			return ExecuteBeadReport{BeadID: beadID, Status: ExecuteBeadStatusSuccess}, nil
		}),
	}

	// Fabricate a typed-incompatibility error via the upstream test seam:
	// the preflight callback returns the same error type that upstream
	// ResolveRoute returns when a harness allow-list rejects the model.
	rejected := agentlib.ErrHarnessModelIncompatible{
		Harness:         "claude",
		Model:           "gpt-5",
		SupportedModels: []string{"claude-opus-4-7", "claude-sonnet-4-6"},
	}
	var preflightCalls int32
	preflight := func(ctx context.Context, harness, model string) error {
		atomic.AddInt32(&preflightCalls, 1)
		return rejected
	}

	cfgOpts := config.TestLoopConfigOpts{
		Assignee: "worker",
		Harness:  "claude",
		Model:    "gpt-5",
	}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:           true,
		RoutePreflight: preflight,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	// AC#1: preflight ran exactly once during startup.
	assert.Equal(t, int32(1), atomic.LoadInt32(&preflightCalls), "preflight must be invoked")

	// AC#2: Claim was NEVER called on the store.
	assert.Equal(t, int32(0), atomic.LoadInt32(&store.claimCalls),
		"beadStore.Claim must not be called when preflight rejects")

	// Executor must not have been invoked either.
	assert.Equal(t, int32(0), atomic.LoadInt32(&execCount),
		"executor must not run when preflight rejects")

	// AC#3: startup failure is surfaced once as a worker-level
	// execution_failed record before any bead-specific attempt exists.
	require.Len(t, result.Results, 1, "exactly one worker-level failure record")
	report := result.Results[0]
	assert.Equal(t, ExecuteBeadStatusExecutionFailed, report.Status)
	assert.Empty(t, report.BeadID)
	assert.Equal(t, "claude", report.Harness)
	assert.Equal(t, "gpt-5", report.Model)
	assert.Contains(t, report.Detail, "claude", "detail must name rejected harness")
	assert.Contains(t, report.Detail, "gpt-5", "detail must name rejected model")
	assert.Equal(t, ExecuteBeadStatusExecutionFailed, result.LastFailureStatus)
	assert.Equal(t, 1, result.Failures)
	assert.Equal(t, 0, result.Attempts)
	assert.Equal(t, "Preflight", result.StopCondition)
	assert.Equal(t, "preflight_failed", result.ExitReason)

	// AC#4: no bead-specific attempt events were appended.
	events, err := store.Events(candidate.ID)
	require.NoError(t, err)
	for _, ev := range events {
		assert.NotEqual(t, "power-attempt", ev.Kind,
			"no power-attempt event must be recorded when preflight rejects at startup")
	}

	// Bead must remain open with no owner — confirms no Claim side-effects.
	got, err := store.Get(context.Background(), candidate.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status)
	assert.Empty(t, got.Owner)
}

// TestRoutingPreflightSuccessAllowsClaim verifies the gate is non-disruptive
// on the happy path: when RoutePreflight returns nil the loop proceeds to
// Claim and executor as normal.
func TestRoutingPreflightSuccessAllowsClaim(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	var execCount int32
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			atomic.AddInt32(&execCount, 1)
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-ok",
				ResultRev: "abc1234",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", Harness: "claude", Model: "claude-opus-4-7"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once: true,
		RoutePreflight: func(ctx context.Context, harness, model string) error {
			return nil
		},
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "Claim must run when preflight passes")
	assert.Equal(t, int32(1), atomic.LoadInt32(&execCount), "executor must run when preflight passes")
	assert.Equal(t, 1, result.Successes)

	got, err := store.Get(context.Background(), candidate.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusClosed, got.Status)
}

// Package failclass implements the FEAT-004 failure-classification routing
// policy applied by ddx work between bead-execution attempts (bead
// ddx-d27a1895).
//
// It provides four things the queue drain composes:
//
//   - Classify maps a single attempt Outcome to exactly one routing Action,
//     applying the normative failure-classification table.
//   - Escalate owns the single one-hop middle->max tier escalation, which only
//     a typed genuine failure triggers.
//   - Pool enforces a per-pool in-flight max-attempt cap that prevents a
//     multi-worker stampede when many workers fail concurrently.
//   - Pool also carries the global (per-pool, not per-bead) cooldown applied on
//     quota exhaustion.
//
// The classification table is normative; it is inlined here from the bead body
// because the upstream FEAT-004 routing addendum lives in the fizeau repo and
// is not reachable from a cold ddx agent.
package failclass

import (
	"sync"
	"time"
)

// Outcome is the typed result of a single ddx-work attempt. Every Outcome maps
// to exactly one Action via Classify.
type Outcome string

const (
	// OutcomeSuccess: the attempt satisfied the bead's acceptance criteria.
	OutcomeSuccess Outcome = "success"
	// OutcomeAlreadySatisfied: the bead was already satisfied before work.
	OutcomeAlreadySatisfied Outcome = "already_satisfied"
	// OutcomeNoChanges: the agent produced nothing and wrote a rationale.
	OutcomeNoChanges Outcome = "no_changes"
	// OutcomeGenuineFailure: tests fail after real work; acceptance unmet.
	// This is the only outcome that can trigger a tier escalation.
	OutcomeGenuineFailure Outcome = "genuine_failure"
	// OutcomeDirtyWorktree: dirty worktree or partial write.
	OutcomeDirtyWorktree Outcome = "dirty_worktree"
	// OutcomeTransport: provider transport failure (i/o timeout, conn refused,
	// 5xx).
	OutcomeTransport Outcome = "transport"
	// OutcomeQuota: quota exhausted (retry_after).
	OutcomeQuota Outcome = "quota"
	// OutcomeAuth: auth/config missing.
	OutcomeAuth Outcome = "auth"
	// OutcomeSetup: toolchain/setup failure.
	OutcomeSetup Outcome = "setup"
	// OutcomeTimeout: timeout / no-progress watchdog.
	OutcomeTimeout Outcome = "timeout"
	// OutcomeMergeConflict: merge/land conflict.
	OutcomeMergeConflict Outcome = "merge_conflict"
)

// Action is the single routing action selected for an Outcome.
type Action string

const (
	// ActionCloseBead: close the bead (success path).
	ActionCloseBead Action = "close_bead"
	// ActionCloseOrUnclaim: close or unclaim per the agent's rationale; never
	// escalate the tier.
	ActionCloseOrUnclaim Action = "close_or_unclaim"
	// ActionEscalateTier: escalate the tier exactly once (middle->max).
	ActionEscalateTier Action = "escalate_tier"
	// ActionResetRetrySameTier: clean/reset the worktree and retry at the same
	// tier (not an escalation).
	ActionResetRetrySameTier Action = "reset_retry_same_tier"
	// ActionRerouteSameTier: reroute to another dispatchable candidate at the
	// same tier; no tier change.
	ActionRerouteSameTier Action = "reroute_same_tier"
	// ActionGlobalCooldown: put the whole pool to sleep until quota reset; not
	// a per-bead mutation, not an escalation.
	ActionGlobalCooldown Action = "global_cooldown"
	// ActionOperatorAttention: explicit bead state transition to the operator
	// lane (not a notification or an indefinite wait).
	ActionOperatorAttention Action = "operator_attention"
	// ActionUnclaimRetryLater: unclaim and retry later; not an escalation.
	ActionUnclaimRetryLater Action = "unclaim_retry_later"
)

// Escalates reports whether the Action mutates the tier. Only
// ActionEscalateTier escalates; this is the single guard the escalation owner
// (ddx work) checks before calling Escalate.
func (a Action) Escalates() bool {
	return a == ActionEscalateTier
}

// ClassifyContext carries the routing state needed to resolve the tier- and
// attempt-conditional rows of the table (genuine failure and timeout).
type ClassifyContext struct {
	// AtMaxTier reports whether the attempt already ran at the maximum tier. A
	// genuine failure at the max tier goes to the operator lane instead of
	// escalating.
	AtMaxTier bool
	// SameTierRetried reports whether a same-tier retry was already consumed. A
	// second timeout (after one same-tier retry) goes to the operator lane.
	SameTierRetried bool
}

// Classify maps a single attempt Outcome to exactly one Action, applying the
// normative failure-classification table.
//
// Only OutcomeGenuineFailure can produce ActionEscalateTier, and only when the
// attempt was not already at the max tier. The no_changes, dirty, transport,
// quota, auth, setup, timeout, and merge-conflict outcomes never escalate.
func Classify(outcome Outcome, ctx ClassifyContext) Action {
	switch outcome {
	case OutcomeSuccess, OutcomeAlreadySatisfied:
		return ActionCloseBead
	case OutcomeNoChanges:
		return ActionCloseOrUnclaim
	case OutcomeGenuineFailure:
		// Single one-hop middle->max escalation; a max-tier genuine failure
		// stops escalating and goes to the operator lane.
		if ctx.AtMaxTier {
			return ActionOperatorAttention
		}
		return ActionEscalateTier
	case OutcomeDirtyWorktree:
		return ActionResetRetrySameTier
	case OutcomeTransport:
		return ActionRerouteSameTier
	case OutcomeQuota:
		return ActionGlobalCooldown
	case OutcomeAuth, OutcomeSetup:
		return ActionOperatorAttention
	case OutcomeTimeout:
		// Clean + same-tier retry once, then operator-attention.
		if ctx.SameTierRetried {
			return ActionOperatorAttention
		}
		return ActionResetRetrySameTier
	case OutcomeMergeConflict:
		return ActionUnclaimRetryLater
	default:
		// Unknown outcomes go to the operator lane rather than silently
		// escalating or retrying.
		return ActionOperatorAttention
	}
}

// Tier is a routing capability tier. Escalation is a single one-hop edge from
// TierMiddle to TierMax; no other edge escalates.
type Tier int

const (
	// TierLow is the cheapest tier and is never an escalation target.
	TierLow Tier = iota
	// TierMiddle is the default starting tier for dispatch.
	TierMiddle
	// TierMax is the strongest tier and the only escalation target.
	TierMax
)

// Escalate performs the single one-hop middle->max escalation and reports
// whether it changed the tier. Escalation is idempotent: only TierMiddle
// escalates (to TierMax); every other tier — including a tier already at
// TierMax — is returned unchanged with escalated=false. This enforces "exactly
// one middle->max" per dispatch chain.
func Escalate(t Tier) (next Tier, escalated bool) {
	if t == TierMiddle {
		return TierMax, true
	}
	return t, false
}

// Pool tracks per-pool in-flight attempts and the global cooldown for a single
// dispatch pool. It is safe for concurrent use by multiple workers.
//
// The in-flight cap prevents a multi-worker stampede: when many workers fail
// concurrently against the same pool, at most maxInFlight attempts may hold a
// slot at once. The cooldown is global to the pool (applied on quota
// exhaustion), not a per-bead mutation.
type Pool struct {
	mu            sync.Mutex
	name          string
	maxInFlight   int
	inFlight      int
	cooldownUntil time.Time
	now           func() time.Time
}

// NewPool returns a Pool with the given name and in-flight cap. A non-positive
// maxInFlight is clamped to 1. The clock defaults to time.Now and can be
// overridden for tests via SetClock.
func NewPool(name string, maxInFlight int) *Pool {
	if maxInFlight < 1 {
		maxInFlight = 1
	}
	return &Pool{
		name:        name,
		maxInFlight: maxInFlight,
		now:         time.Now,
	}
}

// SetClock overrides the pool's time source. It exists so tests can advance
// time without sleeping; the bead requires bounded, non-hanging tests.
func (p *Pool) SetClock(now func() time.Time) {
	p.mu.Lock()
	defer p.mu.Unlock()
	p.now = now
}

// Name returns the pool's name.
func (p *Pool) Name() string {
	return p.name
}

// Acquire attempts to take one in-flight slot. It returns false when the pool
// is in cooldown or the in-flight cap is already reached; otherwise it takes a
// slot and returns true. Every successful Acquire must be paired with a
// Release.
func (p *Pool) Acquire() bool {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.now().Before(p.cooldownUntil) {
		return false
	}
	if p.inFlight >= p.maxInFlight {
		return false
	}
	p.inFlight++
	return true
}

// Release returns one in-flight slot. It never drops below zero.
func (p *Pool) Release() {
	p.mu.Lock()
	defer p.mu.Unlock()
	if p.inFlight > 0 {
		p.inFlight--
	}
}

// InFlight returns the current number of held in-flight slots.
func (p *Pool) InFlight() int {
	p.mu.Lock()
	defer p.mu.Unlock()
	return p.inFlight
}

// EnterCooldown applies a global pool cooldown of duration d (typically the
// quota retry_after). It is global to the pool, not a per-bead mutation:
// subsequent Acquire calls fail until the cooldown elapses. A later, longer
// cooldown extends the window; a shorter one never shortens an active window.
func (p *Pool) EnterCooldown(d time.Duration) {
	p.mu.Lock()
	defer p.mu.Unlock()
	until := p.now().Add(d)
	if until.After(p.cooldownUntil) {
		p.cooldownUntil = until
	}
}

