				OutcomeReason: "intake_block",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "decomposition",
			report: ExecuteBeadReport{
				Status:    ExecuteBeadStatusDeclinedNeedsDecomposition,
				BaseRev:   "abc123",
				ResultRev: "abc123",
			},
		},
		{
			name: "claim_race",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "claim_race",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "routing_preflight",
			report: ExecuteBeadReport{
				Status:           ExecuteBeadStatusExecutionFailed,
				OutcomeReason:    "preflight_failed",
				Disrupted:        true,
				DisruptionReason: "preflight_rejected",
				BaseRev:          "abc123",
				ResultRev:        "abc123",
			},
		},
		{
			name: "quota",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "quota",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "transport",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: "transport",
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "auth_tool_setup",
			report: ExecuteBeadReport{
				Status:        ExecuteBeadStatusExecutionFailed,
				OutcomeReason: FailureModeAuthError,
				BaseRev:       "abc123",
				ResultRev:     "abc123",
			},
		},
		{
			name: "review_error",
			report: ExecuteBeadReport{
				Status:    ExecuteBeadStatusReviewMalfunction,
				BaseRev:   "abc123",
				ResultRev: "abc123",
